"use strict";parserFactory.register("xbiquge.so",()=>new XbiqugeParser);class XbiqugeParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("div#list");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("div#content")}extractTitleImpl(e){return e.querySelector("h1")}extractLanguage(){return"cn"}findChapterTitle(e){return e.querySelector("div.bookname h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div#fmimg")}async fetchChapter(e){let r={makeTextDecoder:()=>new TextDecoder("gbk")};return(await HttpClient.wrapFetch(e,r)).responseXML}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#info")]}}